import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.jsoup.nodes.Document;
import org.jsoup.parser.Parser;
import okhttp3.mockwebserver.MockResponse;
import okhttp3.mockwebserver.MockWebServer;

import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.net.MalformedURLException;
import java.net.URL;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;

import static org.junit.jupiter.api.Assertions.*;

public class Jsoup_parse_0_Test {

    @Test
    @DisplayName("parse(html, baseUri) with non-empty html and baseUri resolves relative links")
    public void test_TC01_parse_S_S() {
        String html = "<a href=\"page.html\">link</a>";
        String baseUri = "http://example.com/sub/";
        Document doc = Jsoup.parse(html, baseUri);
        assertEquals("http://example.com/sub/page.html",
                doc.select("a").first().absUrl("href"));
    }

    @Test
    @DisplayName("parse(html, \"") with non-empty html uses empty baseUri")
    public void test_TC02_parse_S_emptyBase() {
        String html = "<img src=\"img.png\">";
        String baseUri = "";
        Document doc = Jsoup.parse(html, baseUri);
        assertEquals("", doc.select("img").first().absUrl("src"));
    }

    @Test
    @DisplayName("parse(html) delegates to parse(html, \"")")
    public void test_TC03_parse_S() {
        String html = "<p>test</p>";
        Document doc1 = Jsoup.parse(html);
        Document doc2 = Jsoup.parse(html, "");
        assertEquals(doc2.outerHtml(), doc1.outerHtml());
    }

    @Test
    @DisplayName("parse(html, baseUri, parser) uses provided Parser")
    public void test_TC04_parse_S_S_P() {
        String html = "<x/>";
        String baseUri = "u";
        Parser custom = Parser.xmlParser();
        Document doc = Jsoup.parse(html, baseUri, custom);
        assertEquals(1, doc.select("x").size());
    }

    @Test
    @DisplayName("parse(html, parser) delegates with empty baseUri")
    public void test_TC05_parse_S_P() {
        String html = "<a/>";
        Parser parser = Parser.htmlParser();
        Document doc = Jsoup.parse(html, parser);
        assertEquals(1, doc.select("a").size());
    }

    @Test
    @DisplayName("parse(file, charsetName, baseUri) reads file and parses")
    public void test_TC06_parse_File_valid() throws IOException {
        Path temp = Files.createTempFile("jsoup_test", ".html");
        Files.write(temp, "<b>bold</b>".getBytes(StandardCharsets.UTF_8));
        File f = temp.toFile();
        String cs = "UTF-8";
        String base = "u";
        Document doc = Jsoup.parse(f, cs, base);
        assertEquals("bold", doc.select("b").text());
    }

    @Test
    @DisplayName("parse(file, null, baseUri) uses BOM/meta and returns Document")
    public void test_TC07_parse_File_nullCharset_throws() throws IOException {
        Path temp = Files.createTempFile("jsoup_bom", ".html");
        try (FileOutputStream out = new FileOutputStream(temp.toFile())) {
            out.write(new byte[]{(byte)0xEF, (byte)0xBB, (byte)0xBF});
            out.write("<i>italic</i>".getBytes(StandardCharsets.UTF_8));
        }
        Document doc = Jsoup.parse(temp.toFile(), null, "u");
        assertEquals("italic", doc.select("i").text());
    }

    @Test
    @DisplayName("parse(nonexistentFile,cs,baseUri) throws IOException")
    public void test_TC08_parse_File_notFound_throws() {
        File f = new File("doesnotexist.html");
        assertThrows(IOException.class, () -> Jsoup.parse(f, "UTF-8", "u"));
    }

    @Test
    @DisplayName("parse(URL, timeout) with valid URL returns Document")
    public void test_TC09_parse_URL_timeout() throws IOException {
        try (MockWebServer server = new MockWebServer()) {
            server.enqueue(new MockResponse().setBody("<h1>hi</h1>").addHeader("Content-Type", "text/html"));
            server.start();
            URL url = server.url("/").url();
            int timeout = 1000;
            Document doc = Jsoup.parse(url, timeout);
            assertEquals("hi", doc.select("h1").text());
        }
    }

    @Test
    @DisplayName("parse(URL, timeout) with non-http URL throws MalformedURLException")
    public void test_TC10_parse_URL_malformed_throws() throws IOException {
        URL url = new URL("ftp://example.com");
        assertThrows(MalformedURLException.class, () -> Jsoup.parse(url, 1000));
    }
}
